import React, { useEffect, useState } from "react";
import { Trash2, Pencil, Plus } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const API = "http://localhost:5000/api/links";

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [view, setView] = useState("home"); // home | add
  const [sortBy, setSortBy] = useState("order");

  const [name, setName] = useState("");
  const [order, setOrder] = useState(0);
  const [isActive, setIsActive] = useState(true);

  /* ================= FETCH ================= */
  const fetchLinks = async () => {
    const res = await fetch(API);
    const data = await res.json();

    const parentLinks = data.filter((l) => !l.parent);
    setLinks(parentLinks);
  };

  useEffect(() => {
    fetchLinks();
  }, []);

  /* ================= SORT ================= */
  const sortedLinks = [...links].sort((a, b) => {
    if (sortBy === "name") return a.name.localeCompare(b.name);
    if (sortBy === "status") return b.isActive - a.isActive;
    return a.order - b.order;
  });

  /* ================= SUBMIT ================= */
  const handleSubmit = async (e) => {
    e.preventDefault();

    await fetch(API, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        name,
        order,
        isActive,
        parent: null,
      }),
    });

    setName("");
    setOrder(0);
    setIsActive(true);
    setView("home");
    fetchLinks();
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>

        {/* HEADER */}
        <div className={design.header}>
          <h1 className={design.title}>Parent Navigation Links</h1>
          <p className={design.subtitle}>
            Manage main menu items only.
          </p>

          {/* PATH */}
          <div className={design.pathWrapper}>
            <span
              onClick={() => setView("home")}
              className={design.pathLink}
            >
              linkhome
            </span>

            {view === "add" && (
              <>
                <span className="mx-1">/</span>
                <span className={design.pathActive}>
                  add-link
                </span>
              </>
            )}
          </div>
        </div>

        {/* NAVBAR */}
        <div className={design.navbar}>
          {view === "home" && (
            <button
              onClick={() => setView("add")}
              className={design.darkButton}
            >
              <Plus size={16} />
              Add Link
            </button>
          )}
        </div>

        {/* ================= HOME VIEW ================= */}
        {view === "home" && (
          <div className={design.table}>
            {sortedLinks.map((link) => (
              <div key={link._id} className={design.row}>
                <div>{link.name}</div>
                <div>{link.order}</div>
                <div>
                  {link.isActive ? "Active" : "Inactive"}
                </div>
                <div className="flex justify-end gap-4">
                  <Pencil size={16} className="cursor-pointer" />
                  <Trash2 size={16} className="cursor-pointer text-red-500" />
                </div>
              </div>
            ))}
          </div>
        )}

        {/* ================= ADD VIEW ================= */}
        <AnimatePresence>
          {view === "add" && (
            <motion.div
              initial={{ opacity: 0, y: 15 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className={design.addWrapper}
            >
              {/* LEFT - SORT */}
              <div className={design.sortSection}>
                <label className={design.sortLabel}>
                  Sort By
                </label>
                <select
                  value={sortBy}
                  onChange={(e) => setSortBy(e.target.value)}
                  className={design.select}
                >
                  <option value="order">Order</option>
                  <option value="name">Name</option>
                  <option value="status">Status</option>
                </select>
              </div>

              {/* RIGHT - FORM */}
              <form
                onSubmit={handleSubmit}
                className={design.form}
              >
                <input
                  type="text"
                  placeholder="Link Name"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className={design.input}
                />

                <input
                  type="number"
                  placeholder="Order"
                  value={order}
                  onChange={(e) => setOrder(Number(e.target.value))}
                  className={design.input}
                />

                <select
                  value={isActive}
                  onChange={(e) =>
                    setIsActive(e.target.value === "true")
                  }
                  className={design.input}
                >
                  <option value="true">Active</option>
                  <option value="false">Inactive</option>
                </select>

                <button
                  type="submit"
                  className={design.darkButtonFull}
                >
                  Create Link
                </button>
              </form>
            </motion.div>
          )}
        </AnimatePresence>

      </div>
    </div>
  );
};

export default LinkHome;
